import{Et as e,Ht as t,Rt as n,St as r,wt as i,yt as a}from"./element-plus-v-Ml_4hZ.js";import{n as o}from"./index-C1uKVy4f.js";import{t as s}from"./BackButton-CKUvS6GE.js";var c={name:`PrivacyPolicy`,components:{BackButton:s}},l={class:`legal-page`},u={class:`container`},d={class:`page-header`};function f(o,s,c,f,p,m){let h=t(`BackButton`);return n(),r(`div`,l,[a(`div`,u,[a(`div`,d,[e(h),s[0]||=a(`h1`,{class:`page-title`},`隐私政策`,-1)]),s[1]||=i(`<div class="legal-content card" data-v-0344983e><div class="legal-section" data-v-0344983e><h2 data-v-0344983e>引言</h2><p data-v-0344983e>太初文化（以下简称&quot;我们&quot;或&quot;本平台&quot;）非常重视用户的隐私和个人信息保护。本隐私政策旨在向您说明我们如何收集、使用、存储和保护您的个人信息。</p><p data-v-0344983e>请您在使用我们的服务前，仔细阅读并理解本隐私政策。一旦您开始使用我们的服务，即表示您同意我们按照本隐私政策收集、使用和保护您的个人信息。</p></div><div class="legal-section" data-v-0344983e><h2 data-v-0344983e>一、我们收集的信息</h2><h3 data-v-0344983e>1.1 您主动提供的信息</h3><ul data-v-0344983e><li data-v-0344983e><strong data-v-0344983e>账户信息</strong>：当您注册账户时，我们可能收集您的昵称、头像等基本信息</li><li data-v-0344983e><strong data-v-0344983e>出生信息</strong>：用于生日性格分析功能，包括出生日期（可选提供时辰）</li><li data-v-0344983e><strong data-v-0344983e>测试记录</strong>：您使用测试功能的历史记录</li><li data-v-0344983e><strong data-v-0344983e>反馈信息</strong>：您向我们提交的反馈、建议或投诉</li></ul><h3 data-v-0344983e>1.2 我们自动收集的信息</h3><ul data-v-0344983e><li data-v-0344983e><strong data-v-0344983e>设备信息</strong>：设备型号、操作系统版本、唯一设备标识符</li><li data-v-0344983e><strong data-v-0344983e>日志信息</strong>：访问时间、浏览记录、IP地址、崩溃日志</li><li data-v-0344983e><strong data-v-0344983e>位置信息</strong>：基于IP地址的大致地理位置（用于优化服务）</li></ul><h3 data-v-0344983e>1.3 特别提示</h3><div class="highlight-box" data-v-0344983e><p data-v-0344983e>⚠️ <strong data-v-0344983e>重要说明</strong>：</p><ul data-v-0344983e><li data-v-0344983e>出生日期信息仅用于<strong data-v-0344983e>娱乐测试</strong>，不具有任何预测功能</li><li data-v-0344983e>我们不会收集您的真实姓名、身份证号等敏感身份信息</li><li data-v-0344983e>您可以选择不提供精确的出生时辰，不影响基本功能使用</li></ul></div></div><div class="legal-section" data-v-0344983e><h2 data-v-0344983e>二、我们如何使用信息</h2><p data-v-0344983e>我们收集您的信息主要用于以下目的：</p><ul data-v-0344983e><li data-v-0344983e><strong data-v-0344983e>提供服务</strong>：为您提供生日性格分析、趣味测试等服务</li><li data-v-0344983e><strong data-v-0344983e>个性化体验</strong>：基于您的历史记录推荐相关内容</li><li data-v-0344983e><strong data-v-0344983e>服务优化</strong>：分析使用数据，改进产品功能和用户体验</li><li data-v-0344983e><strong data-v-0344983e>安全保障</strong>：防范欺诈、恶意行为，保障账户安全</li><li data-v-0344983e><strong data-v-0344983e>合规要求</strong>：遵守法律法规的要求</li></ul><p class="notice" data-v-0344983e>我们承诺不会将您的个人信息用于任何与上述目的无关的用途。</p></div><div class="legal-section" data-v-0344983e><h2 data-v-0344983e>三、信息的存储与保护</h2><h3 data-v-0344983e>3.1 信息存储</h3><ul data-v-0344983e><li data-v-0344983e>您的个人信息存储在安全的服务器上</li><li data-v-0344983e>我们采用加密技术保护数据传输安全</li><li data-v-0344983e>信息保存期限为实现目的所必需的最短时间</li></ul><h3 data-v-0344983e>3.2 安全措施</h3><ul data-v-0344983e><li data-v-0344983e>采用SSL/TLS加密技术保护数据传输</li><li data-v-0344983e>实施严格的访问控制，限制内部人员访问</li><li data-v-0344983e>定期进行安全审计和漏洞扫描</li><li data-v-0344983e>建立应急响应机制，应对安全事件</li></ul><h3 data-v-0344983e>3.3 风险提示</h3><div class="warning-box" data-v-0344983e><p data-v-0344983e>尽管我们采取了合理的安全措施，但互联网传输无法保证100%安全。请您理解，由于技术限制和可能存在的各种恶意手段，我们无法保证信息的绝对安全。</p></div></div><div class="legal-section" data-v-0344983e><h2 data-v-0344983e>四、信息共享与披露</h2><h3 data-v-0344983e>4.1 我们不会共享的信息</h3><p data-v-0344983e>我们不会出售、出租或以其他方式向第三方披露您的个人信息，除非：</p><ul data-v-0344983e><li data-v-0344983e>获得您的明确同意</li><li data-v-0344983e>为提供服务的必要（如技术服务提供商）</li><li data-v-0344983e>法律法规要求或政府机关依法要求</li><li data-v-0344983e>保护我们的合法权益或用户安全</li></ul><h3 data-v-0344983e>4.2 第三方服务</h3><p data-v-0344983e>我们可能使用第三方服务提供商来支持我们的服务，如：</p><ul data-v-0344983e><li data-v-0344983e>云服务提供商（数据存储）</li><li data-v-0344983e>分析服务提供商（使用数据分析）</li><li data-v-0344983e>广告服务提供商（如适用）</li></ul><p data-v-0344983e>这些第三方仅在为我们提供服务所必需的范围内访问您的信息，并受保密义务约束。</p></div><div class="legal-section" data-v-0344983e><h2 data-v-0344983e>五、您的权利</h2><p data-v-0344983e>根据相关法律法规，您对您的个人信息享有以下权利：</p><ul data-v-0344983e><li data-v-0344983e><strong data-v-0344983e>访问权</strong>：查询我们持有的关于您的个人信息</li><li data-v-0344983e><strong data-v-0344983e>更正权</strong>：更正不准确的个人信息</li><li data-v-0344983e><strong data-v-0344983e>删除权</strong>：要求删除您的个人信息</li><li data-v-0344983e><strong data-v-0344983e>限制处理权</strong>：限制我们对您个人信息的处理</li><li data-v-0344983e><strong data-v-0344983e>数据可携带权</strong>：获取您的个人信息副本</li><li data-v-0344983e><strong data-v-0344983e>撤回同意权</strong>：撤回之前给予的同意</li></ul><p data-v-0344983e>如您希望行使上述权利，请通过本政策末尾的联系方式与我们联系。</p></div><div class="legal-section" data-v-0344983e><h2 data-v-0344983e>六、Cookies和类似技术</h2><p data-v-0344983e>我们可能使用Cookies和类似技术来：</p><ul data-v-0344983e><li data-v-0344983e>记住您的登录状态和偏好设置</li><li data-v-0344983e>分析网站流量和用户行为</li><li data-v-0344983e>优化网站性能和用户体验</li></ul><p data-v-0344983e>您可以通过浏览器设置管理或禁用Cookies，但这可能影响某些功能的正常使用。</p></div><div class="legal-section" data-v-0344983e><h2 data-v-0344983e>七、未成年人保护</h2><div class="highlight-box" data-v-0344983e><h3 data-v-0344983e>⚠️ 重要提示</h3><ul data-v-0344983e><li data-v-0344983e>我们的服务<strong data-v-0344983e>不适合14岁以下未成年人</strong>使用</li><li data-v-0344983e>如果您是14-18岁的未成年人，请在监护人指导下使用</li><li data-v-0344983e>我们不会有意收集未成年人的个人信息</li><li data-v-0344983e>如发现收集了未成年人的信息，我们将立即删除</li></ul></div></div><div class="legal-section" data-v-0344983e><h2 data-v-0344983e>八、隐私政策的更新</h2><p data-v-0344983e>我们可能不时更新本隐私政策。更新后的政策将在网站上公布，并注明更新日期。</p><p data-v-0344983e>如隐私政策有重大变更，我们将通过适当方式通知您。继续使用我们的服务即表示您接受更新后的隐私政策。</p></div><div class="legal-section" data-v-0344983e><h2 data-v-0344983e>九、联系我们</h2><p data-v-0344983e>如您对本隐私政策有任何疑问、意见或建议，或希望行使您的权利，请通过以下方式联系我们：</p><div class="contact-box" data-v-0344983e><p data-v-0344983e><strong data-v-0344983e>邮箱</strong>：privacy@taichu.com</p><p data-v-0344983e><strong data-v-0344983e>电话</strong>：400-XXX-XXXX（工作日 9:00-18:00）</p><p data-v-0344983e><strong data-v-0344983e>地址</strong>：[公司地址]</p></div><p data-v-0344983e>我们将在收到您的请求后15个工作日内予以回复。</p></div><div class="legal-footer" data-v-0344983e><p data-v-0344983e>本隐私政策最后更新日期：<strong data-v-0344983e>2024年</strong></p><p data-v-0344983e>© 2024 太初文化 版权所有</p></div></div>`,1)])])}var p=o(c,[[`render`,f],[`__scopeId`,`data-v-0344983e`]]);export{p as default};